                ->when(! empty($accessibleBranchIds), fn ($q) => $q->whereIn(\'branch_id\', $accessibleBranchIds))
                ->sum(\'total_amount\') ?? 0;

            $yesterdaySales = \\Illuminate\\Support\\Facades\\DB::table(\'sales\')
                ->whereDate(\'created_at\', $yesterday)
                ->when(! empty($accessibleBranchIds), fn ($q) => $q->whereIn(\'branch_id\', $accessibleBranchIds))
                ->sum(\'total_amount\') ?? 0;

            $todayTransactions = \\Illuminate\\Support\\Facades\\DB::table(\'sales\')
                ->whereDate(\'created_at\', $today)
                ->when(! empty($accessibleBranchIds), fn ($q) => $q->whereIn(\'branch_id\', $accessibleBranchIds))
                ->count() ?? 0;

            $salesChange = $yesterdaySales > 0 ? \\round((($todaySales - $yesterdaySales) / $yesterdaySales) * 100, 1) : 0;

            \\Illuminate\\Support\\Facades\\Log::info(\'Today sales calculated\', [\'todaySales\' => $todaySales, \'yesterdaySales\' => $yesterdaySales]);
        } catch (\\Exception $e) {
            \\Illuminate\\Support\\Facades\\Log::error(\'Error calculating today sales: \'.$e->getMessage());
            $todaySales = 0;
            $yesterdaySales = 0;
            $todayTransactions = 0;
            $salesChange = 0;
        }

        // 2. Today\'s Profit (Sales - Cost of Goods - Expenses)
        try {
            $todayCostOfGoods = \\Illuminate\\Support\\Facades\\DB::table(\'sale_items\')
                ->join(\'sales\', \'sale_items.sale_id\', \'=\', \'sales.id\')
                ->join(\'stock_ins\', function ($join) {
                    $join->on(\'sale_items.product_id\', \'=\', \'stock_ins.product_id\')
                        ->on(\'sales.branch_id\', \'=\', \'stock_ins.branch_id\');
                })
                ->whereDate(\'sales.created_at\', $today)
                ->when(! empty($accessibleBranchIds), fn ($q) => $q->whereIn(\'sales.branch_id\', $accessibleBranchIds))
                ->selectRaw(\'SUM(sale_items.quantity * stock_ins.price) as cost\')
                ->value(\'cost\') ?? 0;

            $todayExpenses = \\Illuminate\\Support\\Facades\\DB::table(\'expenses\')
                ->whereDate(\'expense_date\', $today)
                ->when(! empty($accessibleBranchIds), fn ($q) => $q->whereIn(\'branch_id\', $accessibleBranchIds))
                ->sum(\'amount\') ?? 0;

            $todayProfit = $todaySales - $todayCostOfGoods - $todayExpenses;

            \\Illuminate\\Support\\Facades\\Log::info(\'Today profit calculated\', [\'costOfGoods\' => $todayCostOfGoods, \'expenses\' => $todayExpenses, \'profit\' => $todayProfit]);
        } catch (\\Exception $e) {
            \\Illuminate\\Support\\Facades\\Log::error(\'Error calculating today profit: \'.$e->getMessage());
            $todayCostOfGoods = 0;
            $todayExpenses = 0;
            $todayProfit = 0;
        }

        // 3. Today\'s Expenses with biggest category
        try {
            $biggestExpenseCategory = \\Illuminate\\Support\\Facades\\DB::table(\'expenses\')
                ->join(\'expense_categories\', \'expenses.expense_category_id\', \'=\', \'expense_categories.id\')
                ->whereDate(\'expenses.expense_date\', $today)
                ->select(\'expense_categories.name\', \\Illuminate\\Support\\Facades\\DB::raw(\'SUM(expenses.amount) as total\'))
                ->groupBy(\'expense_categories.id\', \'expense_categories.name\')
                ->orderByDesc(\'total\')
                ->first();
        } catch (\\Exception $e) {
            \\Illuminate\\Support\\Facades\\Log::error(\'Error fetching biggest expense category: \'.$e->getMessage());
            $biggestExpenseCategory = (object) [\'name\' => \'N/A\', \'total\' => 0];
        }

        // 4. Stock level counts aligned with stock management (per product+branch with stock_ins records)
        try {
