            $lowStockItems = (clone $stockBase)
                ->whereRaw($stockExpr.\' > \'.$minExpr.\' AND \'.$stockExpr.\' <= \'.$lowExpr)
                ->count();

            $criticalStockKpi = $outOfStockItems + $criticalStockItems + $lowStockItems;

